import{_ as e,H as i,f as l,i as t}from"./chunks/framework.DLd0CbzH.js";const u=JSON.parse('{"title":"工具调用","description":"","frontmatter":{},"headers":[],"relativePath":"fe/ai/agent/tool/index.md","filePath":"fe/ai/agent/tool/index.md","lastUpdated":1778250166000}'),n={name:"fe/ai/agent/tool/index.md"};function o(r,a,d,c,s,p){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="工具调用" tabindex="-1">工具调用 <a class="header-anchor" href="#工具调用" aria-label="Permalink to &quot;工具调用&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>LLM 只能基于训练数据生成内容，对于依赖外部数据或服务的问题无法准确回答、可能回答过时信息或编造结果。</p><ul><li>实时数据</li><li>外部系统数据</li><li>私有数据</li><li>精确计算</li></ul><h2 id="function-calling" tabindex="-1">Function Calling <a class="header-anchor" href="#function-calling" aria-label="Permalink to &quot;Function Calling&quot;">​</a></h2><p>通过训练让模型在需要调用工具时、根据提示词中的工具定义输出 JSON 格式的工具调用请求，而不是直接生成结果。外部服务解析 JSON、调用对应工具、把结果返回给模型。</p><p>使模型具备请求调用工具的能力。</p><h2 id="工具定义" tabindex="-1">工具定义 <a class="header-anchor" href="#工具定义" aria-label="Permalink to &quot;工具定义&quot;">​</a></h2><p>包括 3 部分：</p><ul><li>元数据：name/description/version/category 等基本信息</li><li>参数定义：调用工具时每个参数的 name/type/description/required/default 等信息</li><li>函数实现：工具具体逻辑的实现，往往是一个函数</li></ul><p>Agent 启动时，可根据本次任务内容只暴露特定工具，既能节省上下文、也提高模型选择工具的准确率。</p><h2 id="工程兼容" tabindex="-1">工程兼容 <a class="header-anchor" href="#工程兼容" aria-label="Permalink to &quot;工程兼容&quot;">​</a></h2><p>对于模型输出 JSON 的异常情况尽可能做兼容：</p><ul><li>参数类型不匹配：强制类型转换，比如字符串转数字</li><li>数值超出指定范围：自动截断</li></ul><p>对部分工具需要做限流，比如总调用次数限流、滑动窗口时间限流。</p>',15)])])}const _=e(n,[["render",o]]);export{u as __pageData,_ as default};
